using ContosoUniversity.Data;
using Microsoft.EntityFrameworkCore;

namespace ContosoUniversity.Tests.Helpers;

public static class TestDbContextFactory
{
    public static SchoolContext Create(string? dbName = null)
    {
        dbName ??= Guid.NewGuid().ToString();
        var options = new DbContextOptionsBuilder<SchoolContext>()
            .UseInMemoryDatabase(dbName)
            .Options;
        var context = new SchoolContext(options);
        context.Database.EnsureCreated();
        return context;
    }
}

using ContosoUniversity.Models;
using ContosoUniversity.Services;

namespace ContosoUniversity.Tests.Services;

public class NotificationServiceTests : IDisposable
{
    private readonly NotificationService _sut = new();

    public void Dispose() => _sut.Dispose();

    [Fact]
    public void SendNotification_WithDisplayName_EnqueuesNotification()
    {
        _sut.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE, "Admin");

        var result = _sut.ReceiveNotification();

        Assert.NotNull(result);
        Assert.Equal("Student", result.EntityType);
        Assert.Equal("1", result.EntityId);
        Assert.Equal("CREATE", result.Operation);
        Assert.Contains("John Doe", result.Message);
        Assert.Contains("created", result.Message);
        Assert.Equal("Admin", result.CreatedBy);
        Assert.False(result.IsRead);
    }

    [Fact]
    public void SendNotification_WithoutDisplayName_UsesEntityIdInMessage()
    {
        _sut.SendNotification("Course", "42", EntityOperation.UPDATE);

        var result = _sut.ReceiveNotification();

        Assert.NotNull(result);
        Assert.Contains("ID: 42", result.Message);
        Assert.Contains("updated", result.Message);
    }

    [Fact]
    public void SendNotification_WithoutUserName_DefaultsToSystem()
    {
        _sut.SendNotification("Student", "1", EntityOperation.CREATE);

        var result = _sut.ReceiveNotification();

        Assert.NotNull(result);
        Assert.Equal("System", result.CreatedBy);
    }

    [Theory]
    [InlineData(EntityOperation.CREATE, "created")]
    [InlineData(EntityOperation.UPDATE, "updated")]
    [InlineData(EntityOperation.DELETE, "deleted")]
    public void SendNotification_DifferentOperations_GeneratesCorrectMessage(EntityOperation operation, string expectedVerb)
    {
        _sut.SendNotification("Department", "5", "Math", operation);

        var result = _sut.ReceiveNotification();

        Assert.NotNull(result);
        Assert.Contains(expectedVerb, result.Message);
        Assert.Equal(operation.ToString(), result.Operation);
    }

    [Fact]
    public void ReceiveNotification_EmptyQueue_ReturnsNull()
    {
        var result = _sut.ReceiveNotification();

        Assert.Null(result);
    }

    [Fact]
    public void ReceiveNotification_MultipleMessages_ReturnsFIFO()
    {
        _sut.SendNotification("A", "1", EntityOperation.CREATE);
        _sut.SendNotification("B", "2", EntityOperation.UPDATE);

        var first = _sut.ReceiveNotification();
        var second = _sut.ReceiveNotification();

        // Queue is static/shared so we just verify we got notifications back
        Assert.NotNull(first);
        Assert.NotNull(second);
    }

    [Fact]
    public void MarkAsRead_DoesNotThrow()
    {
        // MarkAsRead is a no-op for in-memory implementation
        var exception = Record.Exception(() => _sut.MarkAsRead(999));
        Assert.Null(exception);
    }

    [Fact]
    public void SendNotification_SetsCreatedAtToRecentTime()
    {
        var before = DateTime.Now.AddSeconds(-1);
        _sut.SendNotification("Test", "1", EntityOperation.CREATE);
        var after = DateTime.Now.AddSeconds(1);

        var result = _sut.ReceiveNotification();

        Assert.NotNull(result);
        Assert.InRange(result.CreatedAt, before, after);
    }
}

namespace ContosoUniversity.Tests;

public class PaginatedListTests
{
    [Fact]
    public void Constructor_SetsPropertiesCorrectly()
    {
        var items = new List<string> { "a", "b", "c" };

        var sut = new PaginatedList<string>(items, 10, 2, 3);

        Assert.Equal(2, sut.PageIndex);
        Assert.Equal(4, sut.TotalPages); // ceil(10/3) = 4
        Assert.Equal(3, sut.Count);
        Assert.Contains("a", sut);
    }

    [Theory]
    [InlineData(1, false)]
    [InlineData(2, true)]
    [InlineData(3, true)]
    public void HasPreviousPage_ReturnsCorrectValue(int pageIndex, bool expected)
    {
        var sut = new PaginatedList<int>(new List<int>(), 30, pageIndex, 10);
        Assert.Equal(expected, sut.HasPreviousPage);
    }

    [Theory]
    [InlineData(1, 3, true)]
    [InlineData(2, 3, true)]
    [InlineData(3, 3, false)]
    public void HasNextPage_ReturnsCorrectValue(int pageIndex, int totalPages, bool expected)
    {
        // count = totalPages * pageSize
        var sut = new PaginatedList<int>(new List<int>(), totalPages * 10, pageIndex, 10);
        Assert.Equal(expected, sut.HasNextPage);
    }

    [Fact]
    public void Create_ReturnsCorrectPage()
    {
        var source = Enumerable.Range(1, 25).AsQueryable();

        var result = PaginatedList<int>.Create(source, 2, 10);

        Assert.Equal(2, result.PageIndex);
        Assert.Equal(3, result.TotalPages);
        Assert.Equal(10, result.Count);
        Assert.Equal(11, result[0]); // second page starts at 11
    }

    [Fact]
    public void Create_LastPage_ReturnRemainingItems()
    {
        var source = Enumerable.Range(1, 25).AsQueryable();

        var result = PaginatedList<int>.Create(source, 3, 10);

        Assert.Equal(5, result.Count);
        Assert.Equal(21, result[0]);
    }

    [Fact]
    public void Create_SinglePage_NoNextOrPrevious()
    {
        var source = Enumerable.Range(1, 5).AsQueryable();

        var result = PaginatedList<int>.Create(source, 1, 10);

        Assert.False(result.HasPreviousPage);
        Assert.False(result.HasNextPage);
        Assert.Equal(1, result.TotalPages);
    }
}

