using ContosoUniversity.Models;
using ContosoUniversity.Services;

namespace ContosoUniversity.Tests.Services;

public class NotificationServiceTests : IDisposable
{
    private readonly NotificationService _sut = new();

    public void Dispose() => _sut.Dispose();

    [Fact]
    public void SendNotification_WithDisplayName_EnqueuesNotification()
    {
        _sut.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE, "Admin");

        var result = _sut.ReceiveNotification();

        Assert.NotNull(result);
        Assert.Equal("Student", result.EntityType);
        Assert.Equal("1", result.EntityId);
        Assert.Equal("CREATE", result.Operation);
        Assert.Contains("John Doe", result.Message);
        Assert.Contains("created", result.Message);
        Assert.Equal("Admin", result.CreatedBy);
        Assert.False(result.IsRead);
    }

    [Fact]
    public void SendNotification_WithoutDisplayName_UsesEntityIdInMessage()
    {
        _sut.SendNotification("Course", "42", EntityOperation.UPDATE);

        var result = _sut.ReceiveNotification();

        Assert.NotNull(result);
        Assert.Contains("ID: 42", result.Message);
        Assert.Contains("updated", result.Message);
    }

    [Fact]
    public void SendNotification_WithoutUserName_DefaultsToSystem()
    {
        _sut.SendNotification("Student", "1", EntityOperation.CREATE);

        var result = _sut.ReceiveNotification();

        Assert.NotNull(result);
        Assert.Equal("System", result.CreatedBy);
    }

    [Theory]
    [InlineData(EntityOperation.CREATE, "created")]
    [InlineData(EntityOperation.UPDATE, "updated")]
    [InlineData(EntityOperation.DELETE, "deleted")]
    public void SendNotification_DifferentOperations_GeneratesCorrectMessage(EntityOperation operation, string expectedVerb)
    {
        _sut.SendNotification("Department", "5", "Math", operation);

        var result = _sut.ReceiveNotification();

        Assert.NotNull(result);
        Assert.Contains(expectedVerb, result.Message);
        Assert.Equal(operation.ToString(), result.Operation);
    }

    [Fact]
    public void ReceiveNotification_EmptyQueue_ReturnsNull()
    {
        // Drain any leftover messages from other tests (static queue)
        while (_sut.ReceiveNotification() != null) { }

        var result = _sut.ReceiveNotification();

        Assert.Null(result);
    }

    [Fact]
    public void MarkAsRead_DoesNotThrow()
    {
        var exception = Record.Exception(() => _sut.MarkAsRead(999));
        Assert.Null(exception);
    }

    [Fact]
    public void SendNotification_SetsCreatedAtToRecentTime()
    {
        var before = DateTime.Now.AddSeconds(-1);
        _sut.SendNotification("Test", "1", "TestEntity", EntityOperation.CREATE);
        var after = DateTime.Now.AddSeconds(1);

        var result = _sut.ReceiveNotification();

        Assert.NotNull(result);
        Assert.InRange(result.CreatedAt, before, after);
    }

    [Fact]
    public void SendNotification_NullDisplayName_UsesEntityIdFormat()
    {
        _sut.SendNotification("Instructor", "7", null!, EntityOperation.DELETE);

        var result = _sut.ReceiveNotification();

        Assert.NotNull(result);
        Assert.Contains("ID: 7", result.Message);
    }

    [Fact]
    public void SendNotification_EmptyDisplayName_UsesEntityIdFormat()
    {
        _sut.SendNotification("Instructor", "7", "  ", EntityOperation.DELETE);

        var result = _sut.ReceiveNotification();

        Assert.NotNull(result);
        Assert.Contains("ID: 7", result.Message);
    }
}

