using ContosoUniversity.Models;

namespace ContosoUniversity.Tests.Models;

public class PersonFullNameTests
{
    [Theory]
    [InlineData("Doe", "John", "Doe, John")]
    [InlineData("Smith", "Jane", "Smith, Jane")]
    public void FullName_ReturnsLastNameCommaFirstName(string lastName, string firstName, string expected)
    {
        var student = new Student { LastName = lastName, FirstMidName = firstName };
        Assert.Equal(expected, student.FullName);
    }
}

public class ErrorViewModelTests
{
    [Fact]
    public void ShowRequestId_WhenNotEmpty_ReturnsTrue()
    {
        var model = new ErrorViewModel { RequestId = "abc123" };
        Assert.True(model.ShowRequestId);
    }

    [Theory]
    [InlineData(null)]
    [InlineData("")]
    public void ShowRequestId_WhenNullOrEmpty_ReturnsFalse(string? requestId)
    {
        var model = new ErrorViewModel { RequestId = requestId! };
        Assert.False(model.ShowRequestId);
    }
}

public class NotificationModelTests
{
    [Fact]
    public void Notification_DefaultValues()
    {
        var notification = new Notification();
        Assert.Equal(0, notification.Id);
        Assert.False(notification.IsRead);
        Assert.Null(notification.ReadAt);
    }
}

public class EnrollmentGradeTests
{
    [Fact]
    public void Grade_CanBeNull()
    {
        var enrollment = new Enrollment { CourseID = 1, StudentID = 1 };
        Assert.Null(enrollment.Grade);
    }

    [Fact]
    public void Grade_CanBeSet()
    {
        var enrollment = new Enrollment { Grade = Grade.A };
        Assert.Equal(Grade.A, enrollment.Grade);
    }
}

