using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.EntityFrameworkCore;

namespace ContosoUniversity.Tests.Data;

public class SchoolContextTests
{
    [Fact]
    public void SchoolContext_CanAddAndRetrieveStudent()
    {
        using var context = TestDbContextFactory.Create();

        var student = new Student
        {
            FirstMidName = "Test",
            LastName = "User",
            EnrollmentDate = DateTime.Parse("2023-01-01")
        };
        context.Students.Add(student);
        context.SaveChanges();

        var retrieved = context.Students.First(s => s.LastName == "User");
        Assert.Equal("Test", retrieved.FirstMidName);
    }

    [Fact]
    public void SchoolContext_CourseAssignment_HasCompositeKey()
    {
        using var context = TestDbContextFactory.Create();

        var instructor = new Instructor
        {
            FirstMidName = "Test",
            LastName = "Instructor",
            HireDate = DateTime.Parse("2020-01-01")
        };
        context.Instructors.Add(instructor);

        var dept = new Department
        {
            Name = "TestDept",
            Budget = 1000,
            StartDate = DateTime.Parse("2020-01-01")
        };
        context.Departments.Add(dept);
        context.SaveChanges();

        var course = new Course
        {
            CourseID = 9999,
            Title = "TestCourse",
            Credits = 3,
            DepartmentID = dept.DepartmentID
        };
        context.Courses.Add(course);
        context.SaveChanges();

        var assignment = new CourseAssignment
        {
            CourseID = course.CourseID,
            InstructorID = instructor.ID
        };
        context.CourseAssignments.Add(assignment);
        context.SaveChanges();

        var found = context.CourseAssignments.Find(course.CourseID, instructor.ID);
        Assert.NotNull(found);
    }

    [Fact]
    public void SchoolContext_InstructorOfficeAssignment_OneToOne()
    {
        using var context = TestDbContextFactory.Create();

        var instructor = new Instructor
        {
            FirstMidName = "Office",
            LastName = "Test",
            HireDate = DateTime.Parse("2020-01-01"),
            OfficeAssignment = new OfficeAssignment { Location = "Room 101" }
        };
        context.Instructors.Add(instructor);
        context.SaveChanges();

        var retrieved = context.Instructors
            .Include(i => i.OfficeAssignment)
            .First(i => i.LastName == "Test");
        Assert.NotNull(retrieved.OfficeAssignment);
        Assert.Equal("Room 101", retrieved.OfficeAssignment.Location);
    }

    [Fact]
    public void SchoolContext_TPH_DiscriminatorWorks()
    {
        using var context = TestDbContextFactory.Create();

        context.Students.Add(new Student
        {
            FirstMidName = "S",
            LastName = "Student",
            EnrollmentDate = DateTime.Parse("2023-01-01")
        });
        context.Instructors.Add(new Instructor
        {
            FirstMidName = "I",
            LastName = "Instructor",
            HireDate = DateTime.Parse("2023-01-01")
        });
        context.SaveChanges();

        Assert.Single(context.Students.Where(s => s.LastName == "Student"));
        Assert.Single(context.Instructors.Where(i => i.LastName == "Instructor"));
        Assert.Equal(2, context.People.Count());
    }
}

