using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;

namespace ContosoUniversity.Tests.Controllers;

public class StudentsControllerTests : IDisposable
{
    private readonly SchoolContext _context;
    private readonly StudentsController _controller;

    public StudentsControllerTests()
    {
        _context = TestDbContextFactory.Create();
        SeedStudents();
        _controller = new StudentsController(_context);
    }

    public void Dispose()
    {
        _controller.Dispose();
        _context.Dispose();
    }

    private void SeedStudents()
    {
        _context.Students.AddRange(
            new Student { FirstMidName = "Carson", LastName = "Alexander", EnrollmentDate = DateTime.Parse("2010-09-01") },
            new Student { FirstMidName = "Meredith", LastName = "Alonso", EnrollmentDate = DateTime.Parse("2012-09-01") },
            new Student { FirstMidName = "Arturo", LastName = "Anand", EnrollmentDate = DateTime.Parse("2013-09-01") }
        );
        _context.SaveChanges();
    }

    // --- Index ---

    [Fact]
    public void Index_NoParameters_ReturnsViewWithStudents()
    {
        var result = _controller.Index(null, null, null, null) as ViewResult;

        Assert.NotNull(result);
        var model = Assert.IsType<PaginatedList<Student>>(result.Model);
        Assert.Equal(3, model.Count);
    }

    [Fact]
    public void Index_DefaultSort_OrdersByLastNameAsc()
    {
        var result = _controller.Index(null, null, null, null) as ViewResult;

        var model = Assert.IsType<PaginatedList<Student>>(result!.Model);
        Assert.Equal("Alexander", model[0].LastName);
        Assert.Equal("Alonso", model[1].LastName);
        Assert.Equal("Anand", model[2].LastName);
    }

    [Fact]
    public void Index_NameDescSort_OrdersByLastNameDesc()
    {
        var result = _controller.Index("name_desc", null, null, null) as ViewResult;

        var model = Assert.IsType<PaginatedList<Student>>(result!.Model);
        Assert.Equal("Anand", model[0].LastName);
    }

    [Fact]
    public void Index_DateSort_OrdersByDateAsc()
    {
        var result = _controller.Index("Date", null, null, null) as ViewResult;

        var model = Assert.IsType<PaginatedList<Student>>(result!.Model);
        Assert.Equal("Alexander", model[0].LastName); // 2010
    }

    [Fact]
    public void Index_DateDescSort_OrdersByDateDesc()
    {
        var result = _controller.Index("date_desc", null, null, null) as ViewResult;

        var model = Assert.IsType<PaginatedList<Student>>(result!.Model);
        Assert.Equal("Anand", model[0].LastName); // 2013
    }

    [Fact]
    public void Index_SearchString_FiltersResults()
    {
        var result = _controller.Index(null, null, "Alexander", null) as ViewResult;

        var model = Assert.IsType<PaginatedList<Student>>(result!.Model);
        Assert.Single(model);
        Assert.Equal("Alexander", model[0].LastName);
    }

    [Fact]
    public void Index_SearchString_SetsPageTo1()
    {
        var result = _controller.Index(null, null, "A", null) as ViewResult;

        var model = Assert.IsType<PaginatedList<Student>>(result!.Model);
        Assert.Equal(1, model.PageIndex);
    }

    [Fact]
    public void Index_NullSearchWithCurrentFilter_UsesCurrentFilter()
    {
        var result = _controller.Index(null, "Alonso", null, null) as ViewResult;

        var model = Assert.IsType<PaginatedList<Student>>(result!.Model);
        Assert.Single(model);
    }

    [Fact]
    public void Index_SetsViewBagProperties()
    {
        _controller.Index("Date", null, "test", null);

        Assert.Equal("Date", _controller.ViewBag.CurrentSort);
        Assert.Equal("date_desc", _controller.ViewBag.DateSortParm);
        Assert.Equal("", _controller.ViewBag.NameSortParm);
        Assert.Equal("test", _controller.ViewBag.CurrentFilter);
    }

    [Fact]
    public void Index_EmptySortOrder_SetsNameSortParmToNameDesc()
    {
        _controller.Index(null, null, null, null);

        Assert.Equal("name_desc", _controller.ViewBag.NameSortParm);
        Assert.Equal("Date", _controller.ViewBag.DateSortParm);
    }

    // --- Details ---

    [Fact]
    public void Details_NullId_ReturnsBadRequest()
    {
        var result = _controller.Details(null);

        var statusResult = Assert.IsType<StatusCodeResult>(result);
        Assert.Equal(400, statusResult.StatusCode);
    }

    [Fact]
    public void Details_ValidId_ReturnsStudent()
    {
        var studentId = _context.Students.First().ID;

        var result = _controller.Details(studentId) as ViewResult;

        Assert.NotNull(result);
        var model = Assert.IsType<Student>(result.Model);
        Assert.Equal(studentId, model.ID);
    }

    // --- Create GET ---

    [Fact]
    public void Create_GET_ReturnsViewWithDefaultDate()
    {
        var result = _controller.Create() as ViewResult;

        Assert.NotNull(result);
        var model = Assert.IsType<Student>(result.Model);
        Assert.Equal(DateTime.Today, model.EnrollmentDate);
    }

    // --- Create POST ---

    [Fact]
    public void CreatePost_ValidStudent_RedirectsToIndex()
    {
        var student = new Student
        {
            FirstMidName = "New",
            LastName = "Student",
            EnrollmentDate = DateTime.Parse("2023-01-15")
        };

        var result = _controller.Create(student);

        var redirect = Assert.IsType<RedirectToActionResult>(result);
        Assert.Equal("Index", redirect.ActionName);
        Assert.Equal(4, _context.Students.Count());
    }

    [Fact]
    public void CreatePost_MinDateEnrollment_AddsModelError()
    {
        var student = new Student
        {
            FirstMidName = "Bad",
            LastName = "Date",
            EnrollmentDate = DateTime.MinValue
        };

        var result = _controller.Create(student) as ViewResult;

        Assert.NotNull(result);
        Assert.False(_controller.ModelState.IsValid);
    }

    [Fact]
    public void CreatePost_InvalidModelState_ReturnsView()
    {
        _controller.ModelState.AddModelError("LastName", "Required");
        var student = new Student
        {
            FirstMidName = "Test",
            EnrollmentDate = DateTime.Parse("2023-01-01")
        };

        var result = _controller.Create(student) as ViewResult;

        Assert.NotNull(result);
    }

    // --- Edit GET ---

    [Fact]
    public void Edit_NullId_ReturnsBadRequest()
    {
        var result = _controller.Edit((int?)null);

        var statusResult = Assert.IsType<StatusCodeResult>(result);
        Assert.Equal(400, statusResult.StatusCode);
    }

    [Fact]
    public void Edit_InvalidId_ReturnsNotFound()
    {
        var result = _controller.Edit(9999);

        Assert.IsType<NotFoundResult>(result);
    }

    [Fact]
    public void Edit_ValidId_ReturnsViewWithStudent()
    {
        var studentId = _context.Students.First().ID;

        var result = _controller.Edit(studentId) as ViewResult;

        Assert.NotNull(result);
        var model = Assert.IsType<Student>(result.Model);
        Assert.Equal(studentId, model.ID);
    }

    // --- Edit POST ---

    [Fact]
    public void EditPost_ValidStudent_RedirectsToIndex()
    {
        var existing = _context.Students.First();
        // Detach to avoid tracking conflict
        _context.Entry(existing).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

        var updated = new Student
        {
            ID = existing.ID,
            FirstMidName = "Updated",
            LastName = existing.LastName,
            EnrollmentDate = existing.EnrollmentDate
        };

        var result = _controller.Edit(updated);

        var redirect = Assert.IsType<RedirectToActionResult>(result);
        Assert.Equal("Index", redirect.ActionName);
    }

    [Fact]
    public void EditPost_MinDateEnrollment_AddsModelError()
    {
        var existing = _context.Students.First();
        _context.Entry(existing).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

        var student = new Student
        {
            ID = existing.ID,
            FirstMidName = "Test",
            LastName = "User",
            EnrollmentDate = DateTime.MinValue
        };

        var result = _controller.Edit(student) as ViewResult;

        Assert.NotNull(result);
        Assert.False(_controller.ModelState.IsValid);
    }

    // --- Delete GET ---

    [Fact]
    public void Delete_NullId_ReturnsBadRequest()
    {
        var result = _controller.Delete(null);

        var statusResult = Assert.IsType<StatusCodeResult>(result);
        Assert.Equal(400, statusResult.StatusCode);
    }

    [Fact]
    public void Delete_InvalidId_ReturnsNotFound()
    {
        var result = _controller.Delete(9999);

        Assert.IsType<NotFoundResult>(result);
    }

    [Fact]
    public void Delete_ValidId_ReturnsViewWithStudent()
    {
        var studentId = _context.Students.First().ID;

        var result = _controller.Delete(studentId) as ViewResult;

        Assert.NotNull(result);
        var model = Assert.IsType<Student>(result.Model);
        Assert.Equal(studentId, model.ID);
    }

    // --- DeleteConfirmed ---

    [Fact]
    public void DeleteConfirmed_RemovesStudentAndRedirects()
    {
        var studentId = _context.Students.First().ID;

        var result = _controller.DeleteConfirmed(studentId);

        var redirect = Assert.IsType<RedirectToActionResult>(result);
        Assert.Equal("Index", redirect.ActionName);
        Assert.Equal(2, _context.Students.Count());
    }
}

using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Hosting;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Mvc.Rendering;
using Microsoft.Extensions.Logging;
using Moq;

namespace ContosoUniversity.Tests.Controllers;

public class CoursesControllerTests : IDisposable
{
    private readonly SchoolContext _context;
    private readonly CoursesController _controller;
    private readonly Mock<IWebHostEnvironment> _envMock;
    private readonly Mock<ILogger<CoursesController>> _loggerMock;

    public CoursesControllerTests()
    {
        _context = TestDbContextFactory.Create();
        SeedData();
        _envMock = new Mock<IWebHostEnvironment>();
        _envMock.Setup(e => e.WebRootPath).Returns(Path.GetTempPath());
        _envMock.Setup(e => e.ContentRootPath).Returns(Path.GetTempPath());
        _loggerMock = new Mock<ILogger<CoursesController>>();
        _controller = new CoursesController(_context, _envMock.Object, _loggerMock.Object);
    }

    public void Dispose()
    {
        _controller.Dispose();
        _context.Dispose();
    }

    private void SeedData()
    {
        var dept = new Department
        {
            Name = "Engineering",
            Budget = 100000,
            StartDate = DateTime.Parse("2020-01-01")
        };
        _context.Departments.Add(dept);
        _context.SaveChanges();

        _context.Courses.AddRange(
            new Course { CourseID = 1001, Title = "Intro to CS", Credits = 3, DepartmentID = dept.DepartmentID },
            new Course { CourseID = 1002, Title = "Data Structures", Credits = 4, DepartmentID = dept.DepartmentID }
        );
        _context.SaveChanges();
    }

    // --- Index ---

    [Fact]
    public void Index_ReturnsViewWithCourses()
    {
        var result = _controller.Index() as ViewResult;

        Assert.NotNull(result);
        var model = Assert.IsAssignableFrom<List<Course>>(result.Model);
        Assert.Equal(2, model.Count);
    }

    // --- Details ---

    [Fact]
    public void Details_NullId_ReturnsBadRequest()
    {
        var result = _controller.Details(null);
        var statusResult = Assert.IsType<StatusCodeResult>(result);
        Assert.Equal(400, statusResult.StatusCode);
    }

    [Fact]
    public void Details_ValidId_ReturnsViewWithCourse()
    {
        var result = _controller.Details(1001) as ViewResult;

        Assert.NotNull(result);
        var model = Assert.IsType<Course>(result.Model);
        Assert.Equal("Intro to CS", model.Title);
    }

    // --- Create GET ---

    [Fact]
    public void Create_GET_ReturnsViewWithDepartmentSelectList()
    {
        var result = _controller.Create() as ViewResult;

        Assert.NotNull(result);
        Assert.NotNull(_controller.ViewBag.DepartmentID);
        Assert.IsType<Course>(result.Model);
    }

    // --- Create POST ---

    [Fact]
    public void CreatePost_ValidCourse_RedirectsToIndex()
    {
        var deptId = _context.Departments.First().DepartmentID;
        var course = new Course { CourseID = 2001, Title = "New Course", Credits = 3, DepartmentID = deptId };

        var result = _controller.Create(course, null!);

        var redirect = Assert.IsType<RedirectToActionResult>(result);
        Assert.Equal("Index", redirect.ActionName);
        Assert.Equal(3, _context.Courses.Count());
    }

    [Fact]
    public void CreatePost_InvalidModelState_ReturnsView()
    {
        _controller.ModelState.AddModelError("Title", "Required");
        var course = new Course { CourseID = 3001 };

        var result = _controller.Create(course, null!) as ViewResult;

        Assert.NotNull(result);
    }

    // --- Edit GET ---

    [Fact]
    public void Edit_NullId_ReturnsBadRequest()
    {
        var result = _controller.Edit((int?)null);
        var statusResult = Assert.IsType<StatusCodeResult>(result);
        Assert.Equal(400, statusResult.StatusCode);
    }

    [Fact]
    public void Edit_InvalidId_ReturnsNotFound()
    {
        var result = _controller.Edit(9999);
        Assert.IsType<NotFoundResult>(result);
    }

    [Fact]
    public void Edit_ValidId_ReturnsViewWithCourse()
    {
        var result = _controller.Edit(1001) as ViewResult;

        Assert.NotNull(result);
        var model = Assert.IsType<Course>(result.Model);
        Assert.Equal("Intro to CS", model.Title);
        Assert.NotNull(_controller.ViewBag.DepartmentID);
    }

    // --- Edit POST ---

    [Fact]
    public void EditPost_ValidCourse_RedirectsToIndex()
    {
        var existing = _context.Courses.Find(1001)!;
        _context.Entry(existing).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

        var course = new Course
        {
            CourseID = 1001,
            Title = "Updated Title",
            Credits = 3,
            DepartmentID = existing.DepartmentID
        };

        var result = _controller.Edit(course, null!);

        var redirect = Assert.IsType<RedirectToActionResult>(result);
        Assert.Equal("Index", redirect.ActionName);
    }

    [Fact]
    public void EditPost_InvalidModelState_ReturnsView()
    {
        _controller.ModelState.AddModelError("Title", "Required");
        var course = new Course { CourseID = 1001 };

        var result = _controller.Edit(course, null!) as ViewResult;

        Assert.NotNull(result);
    }

    // --- Delete GET ---

    [Fact]
    public void Delete_NullId_ReturnsBadRequest()
    {
        var result = _controller.Delete(null);
        var statusResult = Assert.IsType<StatusCodeResult>(result);
        Assert.Equal(400, statusResult.StatusCode);
    }

    [Fact]
    public void Delete_ValidId_ReturnsViewWithCourse()
    {
        var result = _controller.Delete(1001) as ViewResult;

        Assert.NotNull(result);
        var model = Assert.IsType<Course>(result.Model);
        Assert.Equal("Intro to CS", model.Title);
    }

    // --- DeleteConfirmed ---

    [Fact]
    public void DeleteConfirmed_RemovesCourseAndRedirects()
    {
        var result = _controller.DeleteConfirmed(1001);

        var redirect = Assert.IsType<RedirectToActionResult>(result);
        Assert.Equal("Index", redirect.ActionName);
        Assert.Single(_context.Courses);
    }
}

