using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Hosting;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Mvc.Rendering;
using Microsoft.Extensions.Logging;
using Moq;

namespace ContosoUniversity.Tests.Controllers;

public class CoursesControllerTests : IDisposable
{
    private readonly SchoolContext _context;
    private readonly CoursesController _controller;
    private readonly Mock<IWebHostEnvironment> _envMock;
    private readonly Mock<ILogger<CoursesController>> _loggerMock;

    public CoursesControllerTests()
    {
        _context = TestDbContextFactory.Create();
        SeedData();
        _envMock = new Mock<IWebHostEnvironment>();
        _envMock.Setup(e => e.WebRootPath).Returns(Path.GetTempPath());
        _envMock.Setup(e => e.ContentRootPath).Returns(Path.GetTempPath());
        _loggerMock = new Mock<ILogger<CoursesController>>();
        _controller = new CoursesController(_context, _envMock.Object, _loggerMock.Object);
    }

    public void Dispose()
    {
        _controller.Dispose();
        _context.Dispose();
    }

    private void SeedData()
    {
        var dept = new Department
        {
            Name = "Engineering",
            Budget = 100000,
            StartDate = DateTime.Parse("2020-01-01")
        };
        _context.Departments.Add(dept);
        _context.SaveChanges();

        _context.Courses.AddRange(
            new Course { CourseID = 1001, Title = "Intro to CS", Credits = 3, DepartmentID = dept.DepartmentID },
            new Course { CourseID = 1002, Title = "Data Structures", Credits = 4, DepartmentID = dept.DepartmentID }
        );
        _context.SaveChanges();
    }

    // --- Index ---

    [Fact]
    public void Index_ReturnsViewWithCourses()
    {
        var result = _controller.Index() as ViewResult;

        Assert.NotNull(result);
        var model = Assert.IsAssignableFrom<List<Course>>(result.Model);
        Assert.Equal(2, model.Count);
    }

    // --- Details ---

    [Fact]
    public void Details_NullId_ReturnsBadRequest()
    {
        var result = _controller.Details(null);
        var statusResult = Assert.IsType<StatusCodeResult>(result);
        Assert.Equal(400, statusResult.StatusCode);
    }

    [Fact]
    public void Details_ValidId_ReturnsViewWithCourse()
    {
        var result = _controller.Details(1001) as ViewResult;

        Assert.NotNull(result);
        var model = Assert.IsType<Course>(result.Model);
        Assert.Equal("Intro to CS", model.Title);
    }

    // --- Create GET ---

    [Fact]
    public void Create_GET_ReturnsViewWithDepartmentSelectList()
    {
        var result = _controller.Create() as ViewResult;

        Assert.NotNull(result);
        Assert.NotNull(_controller.ViewBag.DepartmentID);
        Assert.IsType<Course>(result.Model);
    }

    // --- Create POST ---

    [Fact]
    public void CreatePost_ValidCourse_RedirectsToIndex()
    {
        var deptId = _context.Departments.First().DepartmentID;
        var course = new Course { CourseID = 2001, Title = "New Course", Credits = 3, DepartmentID = deptId };

        var result = _controller.Create(course, null!);

        var redirect = Assert.IsType<RedirectToActionResult>(result);
        Assert.Equal("Index", redirect.ActionName);
        Assert.Equal(3, _context.Courses.Count());
    }

    [Fact]
    public void CreatePost_InvalidModelState_ReturnsView()
    {
        _controller.ModelState.AddModelError("Title", "Required");
        var course = new Course { CourseID = 3001 };

        var result = _controller.Create(course, null!) as ViewResult;

        Assert.NotNull(result);
    }

    // --- Edit GET ---

    [Fact]
    public void Edit_NullId_ReturnsBadRequest()
    {
        var result = _controller.Edit((int?)null);
        var statusResult = Assert.IsType<StatusCodeResult>(result);
        Assert.Equal(400, statusResult.StatusCode);
    }

    [Fact]
    public void Edit_InvalidId_ReturnsNotFound()
    {
        var result = _controller.Edit(9999);
        Assert.IsType<NotFoundResult>(result);
    }

    [Fact]
    public void Edit_ValidId_ReturnsViewWithCourse()
    {
        var result = _controller.Edit(1001) as ViewResult;

        Assert.NotNull(result);
        var model = Assert.IsType<Course>(result.Model);
        Assert.Equal("Intro to CS", model.Title);
        Assert.NotNull(_controller.ViewBag.DepartmentID);
    }

    // --- Edit POST ---

    [Fact]
    public void EditPost_ValidCourse_RedirectsToIndex()
    {
        var existing = _context.Courses.Find(1001)!;
        _context.Entry(existing).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

        var course = new Course
        {
            CourseID = 1001,
            Title = "Updated Title",
            Credits = 3,
            DepartmentID = existing.DepartmentID
        };

        var result = _controller.Edit(course, null!);

        var redirect = Assert.IsType<RedirectToActionResult>(result);
        Assert.Equal("Index", redirect.ActionName);
    }

    [Fact]
    public void EditPost_InvalidModelState_ReturnsView()
    {
        _controller.ModelState.AddModelError("Title", "Required");
        var course = new Course { CourseID = 1001 };

        var result = _controller.Edit(course, null!) as ViewResult;

        Assert.NotNull(result);
