using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;

namespace ContosoUniversity.Tests.Controllers;

public class DepartmentsControllerTests : IDisposable
{
    private readonly SchoolContext _context;
    private readonly DepartmentsController _controller;

    public DepartmentsControllerTests()
    {
        _context = TestDbContextFactory.Create();
        SeedData();
        _controller = new DepartmentsController(_context);
    }

    public void Dispose()
    {
        _controller.Dispose();
        _context.Dispose();
    }

    private void SeedData()
    {
        var instructor = new Instructor
        {
            FirstMidName = "Kim",
            LastName = "Abercrombie",
            HireDate = DateTime.Parse("2000-01-01")
        };
        _context.Instructors.Add(instructor);
        _context.SaveChanges();

        _context.Departments.AddRange(
            new Department { Name = "English", Budget = 350000, StartDate = DateTime.Parse("2007-09-01"), InstructorID = instructor.ID },
            new Department { Name = "Mathematics", Budget = 100000, StartDate = DateTime.Parse("2007-09-01") }
        );
        _context.SaveChanges();
    }

    // --- Index ---

    [Fact]
    public void Index_ReturnsViewWithDepartments()
    {
        var result = _controller.Index() as ViewResult;

        Assert.NotNull(result);
        var model = Assert.IsAssignableFrom<List<Department>>(result.Model);
        Assert.Equal(2, model.Count);
    }

    // --- Details ---

    [Fact]
    public void Details_NullId_ReturnsBadRequest()
    {
        var result = _controller.Details(null);
        Assert.IsType<StatusCodeResult>(result);
    }

    [Fact]
    public void Details_InvalidId_ReturnsNotFound()
    {
        var result = _controller.Details(9999);
        Assert.IsType<NotFoundResult>(result);
    }

    [Fact]
    public void Details_ValidId_ReturnsDepartment()
    {
        var deptId = _context.Departments.First().DepartmentID;

        var result = _controller.Details(deptId) as ViewResult;

        Assert.NotNull(result);
        var model = Assert.IsType<Department>(result.Model);
        Assert.Equal(deptId, model.DepartmentID);
    }

    // --- Create GET ---

    [Fact]
    public void Create_GET_ReturnsViewWithInstructorSelectList()
    {
        var result = _controller.Create() as ViewResult;

        Assert.NotNull(result);
        Assert.NotNull(_controller.ViewBag.InstructorID);
    }

    // --- Create POST ---

    [Fact]
    public void CreatePost_ValidDepartment_RedirectsToIndex()
    {
        var department = new Department
        {
            Name = "Science",
            Budget = 200000,
            StartDate = DateTime.Parse("2023-01-01")
        };

        var result = _controller.Create(department);

        var redirect = Assert.IsType<RedirectToActionResult>(result);
        Assert.Equal("Index", redirect.ActionName);
        Assert.Equal(3, _context.Departments.Count());
    }

    [Fact]
    public void CreatePost_InvalidModelState_ReturnsView()
    {
        _controller.ModelState.AddModelError("Name", "Required");
        var department = new Department();

        var result = _controller.Create(department) as ViewResult;

        Assert.NotNull(result);
        Assert.NotNull(_controller.ViewBag.InstructorID);
    }

    // --- Edit GET ---

    [Fact]
    public void Edit_NullId_ReturnsBadRequest()
    {
        var result = _controller.Edit((int?)null);
        Assert.IsType<StatusCodeResult>(result);
    }

    [Fact]
    public void Edit_InvalidId_ReturnsNotFound()
    {
        var result = _controller.Edit(9999);
        Assert.IsType<NotFoundResult>(result);
    }

    [Fact]
    public void Edit_ValidId_ReturnsViewWithDepartment()
    {
        var deptId = _context.Departments.First().DepartmentID;

        var result = _controller.Edit(deptId) as ViewResult;

        Assert.NotNull(result);
        var model = Assert.IsType<Department>(result.Model);
        Assert.Equal(deptId, model.DepartmentID);
        Assert.NotNull(_controller.ViewBag.InstructorID);
    }

    // --- Edit POST ---

    [Fact]
    public void EditPost_ValidDepartment_RedirectsToIndex()
    {
        var existing = _context.Departments.First();
        _context.Entry(existing).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

        var department = new Department
        {
            DepartmentID = existing.DepartmentID,
            Name = "Updated",
            Budget = existing.Budget,
            StartDate = existing.StartDate,
            InstructorID = existing.InstructorID
        };

        var result = _controller.Edit(department);

        var redirect = Assert.IsType<RedirectToActionResult>(result);
        Assert.Equal("Index", redirect.ActionName);
    }

    [Fact]
    public void EditPost_InvalidModelState_ReturnsView()
    {
        _controller.ModelState.AddModelError("Name", "Required");
        var department = new Department { DepartmentID = _context.Departments.First().DepartmentID };

        var result = _controller.Edit(department) as ViewResult;

        Assert.NotNull(result);
        Assert.NotNull(_controller.ViewBag.InstructorID);
    }

    // --- Delete GET ---

    [Fact]
    public void Delete_NullId_ReturnsBadRequest()
    {
        var result = _controller.Delete(null);
        Assert.IsType<StatusCodeResult>(result);
    }

    [Fact]
    public void Delete_InvalidId_ReturnsNotFound()
    {
        var result = _controller.Delete(9999);
        Assert.IsType<NotFoundResult>(result);
    }

    [Fact]
    public void Delete_ValidId_ReturnsViewWithDepartment()
    {
        var deptId = _context.Departments.First().DepartmentID;

        var result = _controller.Delete(deptId) as ViewResult;

        Assert.NotNull(result);
        Assert.IsType<Department>(result.Model);
    }

    // --- DeleteConfirmed ---

    [Fact]
    public void DeleteConfirmed_RemovesDepartmentAndRedirects()
    {
        var deptId = _context.Departments.First().DepartmentID;

        var result = _controller.DeleteConfirmed(deptId);

        var redirect = Assert.IsType<RedirectToActionResult>(result);
        Assert.Equal("Index", redirect.ActionName);
        Assert.Single(_context.Departments);
    }
}

