using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Models.SchoolViewModels;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;
using Microsoft.EntityFrameworkCore;

namespace ContosoUniversity.Tests.Controllers;

public class InstructorsControllerTests : IDisposable
{
    private readonly SchoolContext _context;
    private readonly InstructorsController _controller;

    public InstructorsControllerTests()
    {
        _context = TestDbContextFactory.Create();
        SeedData();
        _controller = new InstructorsController(_context);
    }

    public void Dispose()
    {
        _controller.Dispose();
        _context.Dispose();
    }

    private void SeedData()
    {
        var dept = new Department
        {
            Name = "Engineering",
            Budget = 100000,
            StartDate = DateTime.Parse("2020-01-01")
        };
        _context.Departments.Add(dept);
        _context.SaveChanges();

        var instructor1 = new Instructor
        {
            FirstMidName = "Kim",
            LastName = "Abercrombie",
            HireDate = DateTime.Parse("2000-01-01"),
            OfficeAssignment = new OfficeAssignment { Location = "Room 101" },
            CourseAssignments = new List<CourseAssignment>()
        };
        var instructor2 = new Instructor
        {
            FirstMidName = "Fadi",
            LastName = "Fakhouri",
            HireDate = DateTime.Parse("2002-07-06"),
            CourseAssignments = new List<CourseAssignment>()
        };
        _context.Instructors.AddRange(instructor1, instructor2);
        _context.SaveChanges();

        var course = new Course
        {
            CourseID = 1050,
            Title = "Chemistry",
            Credits = 3,
            DepartmentID = dept.DepartmentID,
            Enrollments = new List<Enrollment>()
        };
        _context.Courses.Add(course);
        _context.SaveChanges();

        _context.CourseAssignments.Add(new CourseAssignment
        {
            CourseID = course.CourseID,
            InstructorID = instructor1.ID
        });
        _context.SaveChanges();
    }

    // --- Index ---

    [Fact]
    public void Index_NoParameters_ReturnsViewWithInstructors()
    {
        var result = _controller.Index(null, null) as ViewResult;

        Assert.NotNull(result);
        var model = Assert.IsType<InstructorIndexData>(result.Model);
        Assert.Equal(2, model.Instructors.Count());
    }

    [Fact]
    public void Index_WithInstructorId_ShowsCourses()
    {
        var instructorId = _context.Instructors.First(i => i.LastName == "Abercrombie").ID;

        var result = _controller.Index(instructorId, null) as ViewResult;

        Assert.NotNull(result);
        var model = Assert.IsType<InstructorIndexData>(result.Model);
        Assert.NotNull(model.Courses);
        Assert.Single(model.Courses);
    }

    // --- Details ---

    [Fact]
    public void Details_NullId_ReturnsBadRequest()
    {
        var result = _controller.Details(null);
        Assert.IsType<StatusCodeResult>(result);
    }

    [Fact]
    public void Details_InvalidId_ReturnsNotFound()
    {
        var result = _controller.Details(9999);
        Assert.IsType<NotFoundResult>(result);
    }

    [Fact]
    public void Details_ValidId_ReturnsInstructor()
    {
        var id = _context.Instructors.First().ID;

        var result = _controller.Details(id) as ViewResult;

        Assert.NotNull(result);
        var model = Assert.IsType<Instructor>(result.Model);
        Assert.Equal(id, model.ID);
    }

    // --- Create GET ---

    [Fact]
    public void Create_GET_ReturnsViewWithCoursesInViewBag()
    {
        var result = _controller.Create() as ViewResult;

        Assert.NotNull(result);
        var model = Assert.IsType<Instructor>(result.Model);
        Assert.NotNull(model.CourseAssignments);
        Assert.NotNull(_controller.ViewBag.Courses);
    }

    // --- Create POST ---

    [Fact]
    public void CreatePost_ValidInstructor_RedirectsToIndex()
    {
        var instructor = new Instructor
        {
            FirstMidName = "New",
            LastName = "Instructor",
            HireDate = DateTime.Parse("2023-01-01"),
            CourseAssignments = new List<CourseAssignment>()
        };

        var result = _controller.Create(instructor, null!);

        var redirect = Assert.IsType<RedirectToActionResult>(result);
        Assert.Equal("Index", redirect.ActionName);
        Assert.Equal(3, _context.Instructors.Count());
    }

    [Fact]
    public void CreatePost_WithSelectedCourses_AddsCourseAssignments()
    {
        var instructor = new Instructor
        {
            FirstMidName = "Course",
            LastName = "Assigner",
            HireDate = DateTime.Parse("2023-01-01")
        };

        var result = _controller.Create(instructor, new[] { "1050" });

        var redirect = Assert.IsType<RedirectToActionResult>(result);
        Assert.Equal("Index", redirect.ActionName);
    }

    [Fact]
    public void CreatePost_InvalidModelState_ReturnsView()
    {
        _controller.ModelState.AddModelError("LastName", "Required");
        var instructor = new Instructor
        {
            CourseAssignments = new List<CourseAssignment>()
        };

        var result = _controller.Create(instructor, null!) as ViewResult;

        Assert.NotNull(result);
    }

    // --- Edit GET ---

    [Fact]
    public void Edit_NullId_ReturnsBadRequest()
    {
        var result = _controller.Edit((int?)null);
        Assert.IsType<StatusCodeResult>(result);
    }

    [Fact]
    public void Edit_ValidId_ReturnsViewWithInstructor()
    {
        var id = _context.Instructors.First(i => i.LastName == "Abercrombie").ID;

        var result = _controller.Edit(id) as ViewResult;

        Assert.NotNull(result);
        Assert.NotNull(_controller.ViewBag.Courses);
    }

    // --- Delete GET ---

    [Fact]
    public void Delete_NullId_ReturnsBadRequest()
    {
        var result = _controller.Delete(null);
        Assert.IsType<StatusCodeResult>(result);
    }

    [Fact]
    public void Delete_InvalidId_ReturnsNotFound()
    {
        var result = _controller.Delete(9999);
        Assert.IsType<NotFoundResult>(result);
    }

    [Fact]
    public void Delete_ValidId_ReturnsViewWithInstructor()
    {
        var id = _context.Instructors.First().ID;

        var result = _controller.Delete(id) as ViewResult;

        Assert.NotNull(result);
        Assert.IsType<Instructor>(result.Model);
    }

    // --- DeleteConfirmed ---

    [Fact]
    public void DeleteConfirmed_RemovesInstructorAndRedirects()
    {
        var id = _context.Instructors.First(i => i.LastName == "Fakhouri").ID;

        var result = _controller.DeleteConfirmed(id);

        var redirect = Assert.IsType<RedirectToActionResult>(result);
        Assert.Equal("Index", redirect.ActionName);
        Assert.Single(_context.Instructors);
    }

    [Fact]
    public void DeleteConfirmed_InstructorAsDepartmentAdmin_NullifyDepartmentReference()
    {
        var instructor = _context.Instructors.First(i => i.LastName == "Abercrombie");
        var dept = _context.Departments.First();
        dept.InstructorID = instructor.ID;
        _context.SaveChanges();

        _controller.DeleteConfirmed(instructor.ID);

        var updatedDept = _context.Departments.First();
        Assert.Null(updatedDept.InstructorID);
    }
}

