    {
        _controller.Dispose();
        _context.Dispose();
    }

    private void SeedData()
    {
        _context.Students.AddRange(
            new Student { FirstMidName = "A", LastName = "One", EnrollmentDate = DateTime.Parse("2020-01-01") },
            new Student { FirstMidName = "B", LastName = "Two", EnrollmentDate = DateTime.Parse("2020-01-01") },
            new Student { FirstMidName = "C", LastName = "Three", EnrollmentDate = DateTime.Parse("2021-01-01") }
        );
        _context.SaveChanges();
    }

    [Fact]
    public void Index_ReturnsView()
    {
        var result = _controller.Index();
        Assert.IsType<ViewResult>(result);
    }

    [Fact]
    public void About_ReturnsViewWithEnrollmentGroups()
    {
        var result = _controller.About() as ViewResult;

        Assert.NotNull(result);
        var model = Assert.IsAssignableFrom<List<EnrollmentDateGroup>>(result.Model);
        Assert.Equal(2, model.Count); // two distinct dates
    }

    [Fact]
    public void About_GroupsHaveCorrectCounts()
    {
        var result = _controller.About() as ViewResult;

        var model = Assert.IsAssignableFrom<List<EnrollmentDateGroup>>(result!.Model);
        var group2020 = model.First(g => g.EnrollmentDate == DateTime.Parse("2020-01-01"));
        Assert.Equal(2, group2020.StudentCount);
    }

    [Fact]
    public void Contact_ReturnsViewWithMessage()
    {
        var result = _controller.Contact() as ViewResult;

        Assert.NotNull(result);
        Assert.Equal("Your contact page.", _controller.ViewBag.Message);
    }

    [Fact]
    public void Error_ReturnsView()
    {
        var result = _controller.Error();
        Assert.IsType<ViewResult>(result);
    }

    [Fact]
    public void Unauthorized_ReturnsViewWithMessage()
    {
        var result = _controller.Unauthorized() as ViewResult;

        Assert.NotNull(result);
        Assert.Equal("You don't have permission to access this resource.", _controller.ViewBag.Message);
    }
}

