using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Hosting;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.Logging;
using Moq;

namespace ContosoUniversity.Tests.Controllers;

public class CoursesControllerFileUploadTests : IDisposable
{
    private readonly SchoolContext _context;
    private readonly CoursesController _controller;
    private readonly Mock<IWebHostEnvironment> _envMock;
    private readonly string _tempDir;

    public CoursesControllerFileUploadTests()
    {
        _context = TestDbContextFactory.Create();
        _tempDir = Path.Combine(Path.GetTempPath(), Guid.NewGuid().ToString());
        Directory.CreateDirectory(_tempDir);
        SeedData();
        _envMock = new Mock<IWebHostEnvironment>();
        _envMock.Setup(e => e.WebRootPath).Returns(_tempDir);
        _envMock.Setup(e => e.ContentRootPath).Returns(_tempDir);
        var loggerMock = new Mock<ILogger<CoursesController>>();
        _controller = new CoursesController(_context, _envMock.Object, loggerMock.Object);
    }

    public void Dispose()
    {
        _controller.Dispose();
        _context.Dispose();
        try { Directory.Delete(_tempDir, true); } catch { }
    }

    private void SeedData()
    {
        var dept = new Department
        {
            Name = "Engineering",
            Budget = 100000,
            StartDate = DateTime.Parse("2020-01-01")
        };
        _context.Departments.Add(dept);
        _context.SaveChanges();

        _context.Courses.Add(new Course
        {
            CourseID = 1001,
            Title = "Intro to CS",
            Credits = 3,
            DepartmentID = dept.DepartmentID
        });
        _context.SaveChanges();
    }

    private static IFormFile CreateMockFormFile(string fileName, long length)
    {
        var content = new byte[length];
        var stream = new MemoryStream(content);
        var mock = new Mock<IFormFile>();
        mock.Setup(f => f.FileName).Returns(fileName);
        mock.Setup(f => f.Length).Returns(length);
        mock.Setup(f => f.OpenReadStream()).Returns(stream);
        mock.Setup(f => f.CopyTo(It.IsAny<Stream>())).Callback<Stream>(s => stream.CopyTo(s));
        return mock.Object;
    }

    [Fact]
    public void CreatePost_WithValidImage_SavesFileAndRedirects()
    {
        var deptId = _context.Departments.First().DepartmentID;
        var course = new Course { CourseID = 2001, Title = "New Course", Credits = 3, DepartmentID = deptId };
        var file = CreateMockFormFile("test.jpg", 1024);

        var result = _controller.Create(course, file);

        var redirect = Assert.IsType<RedirectToActionResult>(result);
        Assert.Equal("Index", redirect.ActionName);
    }

    [Fact]
    public void CreatePost_WithInvalidExtension_ReturnsViewWithError()
    {
        var deptId = _context.Departments.First().DepartmentID;
        var course = new Course { CourseID = 2002, Title = "Bad Ext", Credits = 3, DepartmentID = deptId };
        var file = CreateMockFormFile("test.exe", 1024);

        var result = _controller.Create(course, file) as ViewResult;

        Assert.NotNull(result);
        Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
    }

    [Fact]
    public void CreatePost_WithOversizedFile_ReturnsViewWithError()
    {
        var deptId = _context.Departments.First().DepartmentID;
        var course = new Course { CourseID = 2003, Title = "Big File", Credits = 3, DepartmentID = deptId };
        var file = CreateMockFormFile("big.jpg", 6 * 1024 * 1024); // 6MB

        var result = _controller.Create(course, file) as ViewResult;

        Assert.NotNull(result);
        Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
    }

    [Fact]
    public void EditPost_WithValidImage_UpdatesAndRedirects()
    {
        var existing = _context.Courses.Find(1001)!;
        _context.Entry(existing).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

        var course = new Course
        {
            CourseID = 1001,
            Title = "Updated",
            Credits = 3,
            DepartmentID = existing.DepartmentID
        };
        var file = CreateMockFormFile("update.png", 1024);

        var result = _controller.Edit(course, file);

        var redirect = Assert.IsType<RedirectToActionResult>(result);
        Assert.Equal("Index", redirect.ActionName);
    }

    [Fact]
    public void EditPost_WithInvalidExtension_ReturnsViewWithError()
    {
        var existing = _context.Courses.Find(1001)!;
        _context.Entry(existing).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

        var course = new Course
        {
            CourseID = 1001,
            Title = "Bad Ext Edit",
            Credits = 3,
            DepartmentID = existing.DepartmentID
        };
        var file = CreateMockFormFile("bad.txt", 1024);

        var result = _controller.Edit(course, file) as ViewResult;

        Assert.NotNull(result);
        Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
    }

    [Fact]
    public void EditPost_WithOversizedFile_ReturnsViewWithError()
    {
        var existing = _context.Courses.Find(1001)!;
        _context.Entry(existing).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

        var course = new Course
        {
            CourseID = 1001,
            Title = "Big Edit",
            Credits = 3,
            DepartmentID = existing.DepartmentID
        };
        var file = CreateMockFormFile("big.jpg", 6 * 1024 * 1024);

        var result = _controller.Edit(course, file) as ViewResult;

        Assert.NotNull(result);
        Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
    }

    [Fact]
    public void DeleteConfirmed_WithImagePath_DeletesFileAndRedirects()
    {
        // Set up a course with an image path
        var course = _context.Courses.Find(1001)!;
        var uploadsDir = Path.Combine(_tempDir, "Uploads", "TeachingMaterials");
        Directory.CreateDirectory(uploadsDir);
        var imagePath = Path.Combine(uploadsDir, "test_image.jpg");
        File.WriteAllText(imagePath, "fake image");
        course.TeachingMaterialImagePath = "/Uploads/TeachingMaterials/test_image.jpg";
        _context.SaveChanges();

        var result = _controller.DeleteConfirmed(1001);

        var redirect = Assert.IsType<RedirectToActionResult>(result);
        Assert.Equal("Index", redirect.ActionName);
        Assert.False(File.Exists(imagePath));
    }

    [Theory]
    [InlineData(".jpg")]
    [InlineData(".jpeg")]
    [InlineData(".png")]
    [InlineData(".gif")]
    [InlineData(".bmp")]
    public void CreatePost_AllowedImageExtensions_AcceptsFile(string ext)
    {
        var deptId = _context.Departments.First().DepartmentID;
        var courseId = 3000 + ext.GetHashCode();
        // Use absolute value to avoid negative IDs
        courseId = Math.Abs(courseId) % 90000 + 10000;
        var course = new Course { CourseID = courseId, Title = $"Course{ext}", Credits = 3, DepartmentID = deptId };
        var file = CreateMockFormFile($"image{ext}", 512);

        var result = _controller.Create(course, file);

        Assert.IsType<RedirectToActionResult>(result);
    }
}

using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;

namespace ContosoUniversity.Tests.Controllers;

public class NotificationsControllerExtendedTests : IDisposable
{
    private readonly SchoolContext _context;
    private readonly NotificationsController _controller;

    public NotificationsControllerExtendedTests()
    {
        _context = TestDbContextFactory.Create();
        _controller = new NotificationsController(_context);
    }

    public void Dispose()
    {
        _controller.Dispose();
        _context.Dispose();
    }

    [Fact]
    public void GetNotifications_WhenNotificationsExist_ReturnsThemInJson()
    {
        // Enqueue a notification via the controller's base class notification service
        // We can use the controller indirectly by triggering an action on another controller
        // But since NotificationService uses a static queue, we can add directly
        var svc = new ContosoUniversity.Services.NotificationService();
        svc.SendNotification("Test", "1", "TestEntity", EntityOperation.CREATE);

        var result = _controller.GetNotifications();

        Assert.IsType<JsonResult>(result);
    }

    [Fact]
    public void MarkAsRead_WithAnyId_ReturnsSuccess()
    {
        var result = _controller.MarkAsRead(42);

        Assert.IsType<JsonResult>(result);
    }

    [Fact]
    public void MarkAsRead_WithZeroId_ReturnsJson()
    {
        var result = _controller.MarkAsRead(0);

        Assert.IsType<JsonResult>(result);
    }
}

using ContosoUniversity.Models;
using ContosoUniversity.Models.SchoolViewModels;

namespace ContosoUniversity.Tests.Models;

public class ModelPropertyTests
{
    // Student
    [Fact]
    public void Student_EnrollmentDate_CanBeSet()
    {
        var date = DateTime.Parse("2023-06-15");
        var student = new Student { EnrollmentDate = date };
        Assert.Equal(date, student.EnrollmentDate);
    }

    [Fact]
    public void Student_Enrollments_DefaultsToNull()
    {
        var student = new Student();
        Assert.Null(student.Enrollments);
    }

    // Person (via Student)
    [Fact]
    public void Person_ID_CanBeSet()
    {
        var student = new Student { ID = 42 };
        Assert.Equal(42, student.ID);
    }

    // Instructor
    [Fact]
    public void Instructor_HireDate_CanBeSet()
    {
        var date = DateTime.Parse("2020-03-15");
        var instructor = new Instructor { HireDate = date };
        Assert.Equal(date, instructor.HireDate);
    }

    [Fact]
    public void Instructor_FullName_Works()
    {
        var instructor = new Instructor { FirstMidName = "Kim", LastName = "Abercrombie" };
        Assert.Equal("Abercrombie, Kim", instructor.FullName);
    }

    [Fact]
    public void Instructor_CourseAssignments_CanBeInitialized()
    {
        var instructor = new Instructor { CourseAssignments = new List<CourseAssignment>() };
        Assert.Empty(instructor.CourseAssignments);
    }

    // Course
    [Fact]
    public void Course_Properties_CanBeSet()
    {
        var course = new Course
        {
            CourseID = 1050,
            Title = "Chemistry",
            Credits = 3,
            DepartmentID = 1,
            TeachingMaterialImagePath = "/images/chem.jpg"
        };
        Assert.Equal(1050, course.CourseID);
        Assert.Equal("Chemistry", course.Title);
        Assert.Equal(3, course.Credits);
        Assert.Equal(1, course.DepartmentID);
        Assert.Equal("/images/chem.jpg", course.TeachingMaterialImagePath);
    }

    [Fact]
    public void Course_NavigationProperties_DefaultToNull()
    {
        var course = new Course();
        Assert.Null(course.Department);
        Assert.Null(course.Enrollments);
        Assert.Null(course.CourseAssignments);
    }

    // Department
    [Fact]
    public void Department_Properties_CanBeSet()
    {
        var dept = new Department
        {
            DepartmentID = 1,
            Name = "Math",
            Budget = 100000m,
            StartDate = DateTime.Parse("2020-01-01"),
            InstructorID = 5,
            RowVersion = new byte[] { 1, 2, 3 }
        };
        Assert.Equal(1, dept.DepartmentID);
        Assert.Equal("Math", dept.Name);
        Assert.Equal(100000m, dept.Budget);
        Assert.Equal(5, dept.InstructorID);
        Assert.Equal(new byte[] { 1, 2, 3 }, dept.RowVersion);
    }

    [Fact]
    public void Department_InstructorID_CanBeNull()
    {
        var dept = new Department { InstructorID = null };
        Assert.Null(dept.InstructorID);
    }

    // CourseAssignment
    [Fact]
    public void CourseAssignment_Properties_CanBeSet()
    {
        var ca = new CourseAssignment { CourseID = 1, InstructorID = 2 };
        Assert.Equal(1, ca.CourseID);
        Assert.Equal(2, ca.InstructorID);
    }

    [Fact]
    public void CourseAssignment_NavigationProperties_DefaultToNull()
    {
        var ca = new CourseAssignment();
        Assert.Null(ca.Instructor);
        Assert.Null(ca.Course);
    }

    // OfficeAssignment
    [Fact]
    public void OfficeAssignment_Properties_CanBeSet()
    {
        var oa = new OfficeAssignment { InstructorID = 1, Location = "Room 101" };
        Assert.Equal(1, oa.InstructorID);
        Assert.Equal("Room 101", oa.Location);
    }

    // Enrollment
    [Fact]
    public void Enrollment_Properties_CanBeSet()
    {
        var enrollment = new Enrollment
        {
            EnrollmentID = 1,
            CourseID = 100,
            StudentID = 200,
            Grade = Grade.B
        };
        Assert.Equal(1, enrollment.EnrollmentID);
        Assert.Equal(100, enrollment.CourseID);
        Assert.Equal(200, enrollment.StudentID);
        Assert.Equal(Grade.B, enrollment.Grade);
    }

    [Fact]
    public void Enrollment_NavigationProperties_DefaultToNull()
    {
        var enrollment = new Enrollment();
        Assert.Null(enrollment.Course);
        Assert.Null(enrollment.Student);
    }

    // Notification
    [Fact]
    public void Notification_AllProperties_CanBeSet()
    {
        var now = DateTime.Now;
        var notification = new Notification
        {
            Id = 1,
            EntityType = "Student",
            EntityId = "42",
            Operation = "CREATE",
            Message = "Student created",
            CreatedAt = now,
            CreatedBy = "Admin",
            IsRead = true,
            ReadAt = now
        };
        Assert.Equal(1, notification.Id);
        Assert.Equal("Student", notification.EntityType);
        Assert.Equal("42", notification.EntityId);
        Assert.Equal("CREATE", notification.Operation);
        Assert.Equal("Student created", notification.Message);
        Assert.Equal(now, notification.CreatedAt);
        Assert.Equal("Admin", notification.CreatedBy);
        Assert.True(notification.IsRead);
        Assert.Equal(now, notification.ReadAt);
    }

    // InstructorIndexData
    [Fact]
    public void InstructorIndexData_Properties_CanBeSet()
    {
        var data = new InstructorIndexData
        {
            Instructors = new List<Instructor>(),
            Courses = new List<Course>(),
            Enrollments = new List<Enrollment>()
        };
        Assert.Empty(data.Instructors);
        Assert.Empty(data.Courses);
        Assert.Empty(data.Enrollments);
    }

    // AssignedCourseData
    [Fact]
    public void AssignedCourseData_Properties_CanBeSet()
    {
        var acd = new AssignedCourseData
        {
            CourseID = 1,
            Title = "Test",
            Assigned = true
        };
        Assert.Equal(1, acd.CourseID);
        Assert.Equal("Test", acd.Title);
        Assert.True(acd.Assigned);
    }

    // EnrollmentDateGroup
    [Fact]
    public void EnrollmentDateGroup_Properties_CanBeSet()
    {
        var group = new EnrollmentDateGroup
        {
            EnrollmentDate = DateTime.Parse("2023-01-01"),
            StudentCount = 5
        };
        Assert.Equal(DateTime.Parse("2023-01-01"), group.EnrollmentDate);
        Assert.Equal(5, group.StudentCount);
    }

    [Fact]
    public void EnrollmentDateGroup_EnrollmentDate_CanBeNull()
    {
        var group = new EnrollmentDateGroup { EnrollmentDate = null };
        Assert.Null(group.EnrollmentDate);
    }

    // EntityOperation enum
    [Theory]
    [InlineData(EntityOperation.CREATE, "CREATE")]
    [InlineData(EntityOperation.UPDATE, "UPDATE")]
    [InlineData(EntityOperation.DELETE, "DELETE")]
    public void EntityOperation_HasExpectedValues(EntityOperation op, string expected)
    {
        Assert.Equal(expected, op.ToString());
    }

    // Grade enum
    [Theory]
    [InlineData(Grade.A, 0)]
    [InlineData(Grade.B, 1)]
    [InlineData(Grade.C, 2)]
    [InlineData(Grade.D, 3)]
    [InlineData(Grade.F, 4)]
    public void Grade_HasExpectedIntValues(Grade grade, int expected)
    {
        Assert.Equal(expected, (int)grade);
    }
}

