using ContosoUniversity.Models;
using ContosoUniversity.Models.SchoolViewModels;

namespace ContosoUniversity.Tests.Models;

public class ModelPropertyTests
{
    // Student
    [Fact]
    public void Student_EnrollmentDate_CanBeSet()
    {
        var date = DateTime.Parse("2023-06-15");
        var student = new Student { EnrollmentDate = date };
        Assert.Equal(date, student.EnrollmentDate);
    }

    [Fact]
    public void Student_Enrollments_DefaultsToNull()
    {
        var student = new Student();
        Assert.Null(student.Enrollments);
    }

    // Person (via Student)
    [Fact]
    public void Person_ID_CanBeSet()
    {
        var student = new Student { ID = 42 };
        Assert.Equal(42, student.ID);
    }

    // Instructor
    [Fact]
    public void Instructor_HireDate_CanBeSet()
    {
        var date = DateTime.Parse("2020-03-15");
        var instructor = new Instructor { HireDate = date };
        Assert.Equal(date, instructor.HireDate);
    }

    [Fact]
    public void Instructor_FullName_Works()
    {
        var instructor = new Instructor { FirstMidName = "Kim", LastName = "Abercrombie" };
        Assert.Equal("Abercrombie, Kim", instructor.FullName);
    }

    [Fact]
    public void Instructor_CourseAssignments_CanBeInitialized()
    {
        var instructor = new Instructor { CourseAssignments = new List<CourseAssignment>() };
        Assert.Empty(instructor.CourseAssignments);
    }

    // Course
    [Fact]
    public void Course_Properties_CanBeSet()
    {
        var course = new Course
        {
            CourseID = 1050,
            Title = "Chemistry",
            Credits = 3,
            DepartmentID = 1,
            TeachingMaterialImagePath = "/images/chem.jpg"
        };
        Assert.Equal(1050, course.CourseID);
        Assert.Equal("Chemistry", course.Title);
        Assert.Equal(3, course.Credits);
        Assert.Equal(1, course.DepartmentID);
        Assert.Equal("/images/chem.jpg", course.TeachingMaterialImagePath);
    }

    [Fact]
    public void Course_NavigationProperties_DefaultToNull()
    {
        var course = new Course();
        Assert.Null(course.Department);
        Assert.Null(course.Enrollments);
        Assert.Null(course.CourseAssignments);
    }

    // Department
    [Fact]
    public void Department_Properties_CanBeSet()
    {
        var dept = new Department
        {
            DepartmentID = 1,
            Name = "Math",
            Budget = 100000m,
            StartDate = DateTime.Parse("2020-01-01"),
            InstructorID = 5,
            RowVersion = new byte[] { 1, 2, 3 }
        };
        Assert.Equal(1, dept.DepartmentID);
        Assert.Equal("Math", dept.Name);
        Assert.Equal(100000m, dept.Budget);
        Assert.Equal(5, dept.InstructorID);
        Assert.Equal(new byte[] { 1, 2, 3 }, dept.RowVersion);
    }

    [Fact]
    public void Department_InstructorID_CanBeNull()
    {
        var dept = new Department { InstructorID = null };
        Assert.Null(dept.InstructorID);
    }

    // CourseAssignment
    [Fact]
    public void CourseAssignment_Properties_CanBeSet()
    {
        var ca = new CourseAssignment { CourseID = 1, InstructorID = 2 };
        Assert.Equal(1, ca.CourseID);
        Assert.Equal(2, ca.InstructorID);
    }

    [Fact]
    public void CourseAssignment_NavigationProperties_DefaultToNull()
    {
        var ca = new CourseAssignment();
        Assert.Null(ca.Instructor);
        Assert.Null(ca.Course);
    }

    // OfficeAssignment
    [Fact]
    public void OfficeAssignment_Properties_CanBeSet()
    {
        var oa = new OfficeAssignment { InstructorID = 1, Location = "Room 101" };
        Assert.Equal(1, oa.InstructorID);
        Assert.Equal("Room 101", oa.Location);
    }

    // Enrollment
    [Fact]
    public void Enrollment_Properties_CanBeSet()
    {
        var enrollment = new Enrollment
        {
            EnrollmentID = 1,
            CourseID = 100,
            StudentID = 200,
            Grade = Grade.B
        };
        Assert.Equal(1, enrollment.EnrollmentID);
        Assert.Equal(100, enrollment.CourseID);
        Assert.Equal(200, enrollment.StudentID);
        Assert.Equal(Grade.B, enrollment.Grade);
    }

    [Fact]
    public void Enrollment_NavigationProperties_DefaultToNull()
    {
        var enrollment = new Enrollment();
        Assert.Null(enrollment.Course);
        Assert.Null(enrollment.Student);
    }

    // Notification
    [Fact]
    public void Notification_AllProperties_CanBeSet()
    {
        var now = DateTime.Now;
        var notification = new Notification
        {
            Id = 1,
            EntityType = "Student",
            EntityId = "42",
            Operation = "CREATE",
            Message = "Student created",
            CreatedAt = now,
            CreatedBy = "Admin",
            IsRead = true,
            ReadAt = now
        };
        Assert.Equal(1, notification.Id);
        Assert.Equal("Student", notification.EntityType);
        Assert.Equal("42", notification.EntityId);
        Assert.Equal("CREATE", notification.Operation);
        Assert.Equal("Student created", notification.Message);
        Assert.Equal(now, notification.CreatedAt);
        Assert.Equal("Admin", notification.CreatedBy);
        Assert.True(notification.IsRead);
        Assert.Equal(now, notification.ReadAt);
    }

    // InstructorIndexData
    [Fact]
    public void InstructorIndexData_Properties_CanBeSet()
    {
        var data = new InstructorIndexData
        {
            Instructors = new List<Instructor>(),
            Courses = new List<Course>(),
            Enrollments = new List<Enrollment>()
        };
        Assert.Empty(data.Instructors);
        Assert.Empty(data.Courses);
        Assert.Empty(data.Enrollments);
    }

    // AssignedCourseData
    [Fact]
    public void AssignedCourseData_Properties_CanBeSet()
    {
        var acd = new AssignedCourseData
        {
            CourseID = 1,
            Title = "Test",
            Assigned = true
        };
        Assert.Equal(1, acd.CourseID);
        Assert.Equal("Test", acd.Title);
        Assert.True(acd.Assigned);
    }

    // EnrollmentDateGroup
    [Fact]
    public void EnrollmentDateGroup_Properties_CanBeSet()
    {
        var group = new EnrollmentDateGroup
        {
            EnrollmentDate = DateTime.Parse("2023-01-01"),
            StudentCount = 5
        };
        Assert.Equal(DateTime.Parse("2023-01-01"), group.EnrollmentDate);
        Assert.Equal(5, group.StudentCount);
    }

    [Fact]
    public void EnrollmentDateGroup_EnrollmentDate_CanBeNull()
    {
        var group = new EnrollmentDateGroup { EnrollmentDate = null };
        Assert.Null(group.EnrollmentDate);
    }

    // EntityOperation enum
    [Theory]
    [InlineData(EntityOperation.CREATE, "CREATE")]
    [InlineData(EntityOperation.UPDATE, "UPDATE")]
    [InlineData(EntityOperation.DELETE, "DELETE")]
    public void EntityOperation_HasExpectedValues(EntityOperation op, string expected)
    {
        Assert.Equal(expected, op.ToString());
    }

    // Grade enum
    [Theory]
    [InlineData(Grade.A, 0)]
    [InlineData(Grade.B, 1)]
    [InlineData(Grade.C, 2)]
    [InlineData(Grade.D, 3)]
    [InlineData(Grade.F, 4)]
    public void Grade_HasExpectedIntValues(Grade grade, int expected)
    {
        Assert.Equal(expected, (int)grade);
    }
}

