using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Hosting;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.Logging;
using Moq;

namespace ContosoUniversity.Tests.Controllers;

public class CoursesControllerFileUploadTests : IDisposable
{
    private readonly SchoolContext _context;
    private readonly CoursesController _controller;
    private readonly Mock<IWebHostEnvironment> _envMock;
    private readonly string _tempDir;

    public CoursesControllerFileUploadTests()
    {
        _context = TestDbContextFactory.Create();
        _tempDir = Path.Combine(Path.GetTempPath(), Guid.NewGuid().ToString());
        Directory.CreateDirectory(_tempDir);
        SeedData();
        _envMock = new Mock<IWebHostEnvironment>();
        _envMock.Setup(e => e.WebRootPath).Returns(_tempDir);
        _envMock.Setup(e => e.ContentRootPath).Returns(_tempDir);
        var loggerMock = new Mock<ILogger<CoursesController>>();
        _controller = new CoursesController(_context, _envMock.Object, loggerMock.Object);
    }

    public void Dispose()
    {
        _controller.Dispose();
        _context.Dispose();
        try { Directory.Delete(_tempDir, true); } catch { }
    }

    private void SeedData()
    {
        var dept = new Department
        {
            Name = "Engineering",
            Budget = 100000,
            StartDate = DateTime.Parse("2020-01-01")
        };
        _context.Departments.Add(dept);
        _context.SaveChanges();

        _context.Courses.Add(new Course
        {
            CourseID = 1001,
            Title = "Intro to CS",
            Credits = 3,
            DepartmentID = dept.DepartmentID
        });
        _context.SaveChanges();
    }

    private static IFormFile CreateMockFormFile(string fileName, long length)
    {
        var content = new byte[length];
        var stream = new MemoryStream(content);
        var mock = new Mock<IFormFile>();
        mock.Setup(f => f.FileName).Returns(fileName);
        mock.Setup(f => f.Length).Returns(length);
        mock.Setup(f => f.OpenReadStream()).Returns(stream);
        mock.Setup(f => f.CopyTo(It.IsAny<Stream>())).Callback<Stream>(s => stream.CopyTo(s));
        return mock.Object;
    }

    [Fact]
    public void CreatePost_WithValidImage_SavesFileAndRedirects()
    {
        var deptId = _context.Departments.First().DepartmentID;
        var course = new Course { CourseID = 2001, Title = "New Course", Credits = 3, DepartmentID = deptId };
        var file = CreateMockFormFile("test.jpg", 1024);

        var result = _controller.Create(course, file);

        var redirect = Assert.IsType<RedirectToActionResult>(result);
        Assert.Equal("Index", redirect.ActionName);
    }

    [Fact]
    public void CreatePost_WithInvalidExtension_ReturnsViewWithError()
    {
        var deptId = _context.Departments.First().DepartmentID;
        var course = new Course { CourseID = 2002, Title = "Bad Ext", Credits = 3, DepartmentID = deptId };
        var file = CreateMockFormFile("test.exe", 1024);

        var result = _controller.Create(course, file) as ViewResult;

        Assert.NotNull(result);
        Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
    }

    [Fact]
    public void CreatePost_WithOversizedFile_ReturnsViewWithError()
    {
        var deptId = _context.Departments.First().DepartmentID;
        var course = new Course { CourseID = 2003, Title = "Big File", Credits = 3, DepartmentID = deptId };
        var file = CreateMockFormFile("big.jpg", 6 * 1024 * 1024); // 6MB

        var result = _controller.Create(course, file) as ViewResult;

        Assert.NotNull(result);
        Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
    }

    [Fact]
    public void EditPost_WithValidImage_UpdatesAndRedirects()
    {
        var existing = _context.Courses.Find(1001)!;
        _context.Entry(existing).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

        var course = new Course
        {
            CourseID = 1001,
            Title = "Updated",
            Credits = 3,
            DepartmentID = existing.DepartmentID
        };
        var file = CreateMockFormFile("update.png", 1024);

        var result = _controller.Edit(course, file);

        var redirect = Assert.IsType<RedirectToActionResult>(result);
        Assert.Equal("Index", redirect.ActionName);
    }

    [Fact]
    public void EditPost_WithInvalidExtension_ReturnsViewWithError()
    {
        var existing = _context.Courses.Find(1001)!;
        _context.Entry(existing).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

        var course = new Course
        {
            CourseID = 1001,
            Title = "Bad Ext Edit",
            Credits = 3,
            DepartmentID = existing.DepartmentID
        };
        var file = CreateMockFormFile("bad.txt", 1024);

        var result = _controller.Edit(course, file) as ViewResult;

        Assert.NotNull(result);
        Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
    }

    [Fact]
    public void EditPost_WithOversizedFile_ReturnsViewWithError()
    {
        var existing = _context.Courses.Find(1001)!;
        _context.Entry(existing).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

        var course = new Course
        {
            CourseID = 1001,
            Title = "Big Edit",
            Credits = 3,
            DepartmentID = existing.DepartmentID
        };
        var file = CreateMockFormFile("big.jpg", 6 * 1024 * 1024);

        var result = _controller.Edit(course, file) as ViewResult;

        Assert.NotNull(result);
        Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
    }

    [Fact]
    public void DeleteConfirmed_WithImagePath_DeletesFileAndRedirects()
    {
        // Set up a course with an image path
        var course = _context.Courses.Find(1001)!;
        var uploadsDir = Path.Combine(_tempDir, "Uploads", "TeachingMaterials");
        Directory.CreateDirectory(uploadsDir);
        var imagePath = Path.Combine(uploadsDir, "test_image.jpg");
        File.WriteAllText(imagePath, "fake image");
        course.TeachingMaterialImagePath = "/Uploads/TeachingMaterials/test_image.jpg";
        _context.SaveChanges();

        var result = _controller.DeleteConfirmed(1001);

        var redirect = Assert.IsType<RedirectToActionResult>(result);
        Assert.Equal("Index", redirect.ActionName);
        Assert.False(File.Exists(imagePath));
    }

    [Theory]
    [InlineData(".jpg")]
    [InlineData(".jpeg")]
    [InlineData(".png")]
    [InlineData(".gif")]
    [InlineData(".bmp")]
    public void CreatePost_AllowedImageExtensions_AcceptsFile(string ext)
    {
        var deptId = _context.Departments.First().DepartmentID;
        var courseId = 3000 + ext.GetHashCode();
        // Use absolute value to avoid negative IDs
        courseId = Math.Abs(courseId) % 90000 + 10000;
        var course = new Course { CourseID = courseId, Title = $"Course{ext}", Credits = 3, DepartmentID = deptId };
        var file = CreateMockFormFile($"image{ext}", 512);

        var result = _controller.Create(course, file);

        Assert.IsType<RedirectToActionResult>(result);
    }
}

