using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;

namespace ContosoUniversity.Tests.Controllers;

public class NotificationsControllerExtendedTests : IDisposable
{
    private readonly SchoolContext _context;
    private readonly NotificationsController _controller;

    public NotificationsControllerExtendedTests()
    {
        _context = TestDbContextFactory.Create();
        _controller = new NotificationsController(_context);
    }

    public void Dispose()
    {
        _controller.Dispose();
        _context.Dispose();
    }

    [Fact]
    public void GetNotifications_WhenNotificationsExist_ReturnsThemInJson()
    {
        // Enqueue a notification via the controller's base class notification service
        // We can use the controller indirectly by triggering an action on another controller
        // But since NotificationService uses a static queue, we can add directly
        var svc = new ContosoUniversity.Services.NotificationService();
        svc.SendNotification("Test", "1", "TestEntity", EntityOperation.CREATE);

        var result = _controller.GetNotifications();

        Assert.IsType<JsonResult>(result);
    }

    [Fact]
    public void MarkAsRead_WithAnyId_ReturnsSuccess()
    {
        var result = _controller.MarkAsRead(42);

        Assert.IsType<JsonResult>(result);
    }

    [Fact]
    public void MarkAsRead_WithZeroId_ReturnsJson()
    {
        var result = _controller.MarkAsRead(0);

        Assert.IsType<JsonResult>(result);
    }
}

